import jwt
import datetime
import hashlib
import base64
import secrets

SECRET_KEY = 'your-secret-key'
ALGORITHM = 'HS256'

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30)
    }

    encoded_payload = jwt.encode(
        payload,
        SECRET_KEY,
        algorithm=ALGORITHM
    )

    return encoded_payload